// Build a structured daily digest message for Discord.
// All counts come from the capture service — no data is stored here.
const d = $input.first().json;

const ts = new Date(d.generated_at).toLocaleString('en-US', {
  timeZone: 'UTC', month: 'short', day: 'numeric',
  hour: '2-digit', minute: '2-digit', hour12: false,
});

const lines = [
  `**Second Brain – Daily Digest** (${ts} UTC)`,
  '',
  '**Intake (last 24 h)**',
  `  New captures: ${d.new_captures_count}`,
  `  Filed notes: ${d.filed_notes_count}`,
  `  Sensitive rejections: ${d.sensitive_rejections_count}`,
];

if (d.attachment_warnings_count > 0) {
  lines.push(`  ⚠️ Pending captures with attachments: ${d.attachment_warnings_count}`);
}

lines.push(
  '',
  '**Backlog**',
  `  Inbox: ${d.inbox_backlog_count}`,
  `  Awaiting clarification: ${d.awaiting_clarification_count}`,
);

if (d.open_tasks_count !== null && d.open_tasks_count !== undefined) {
  lines.push(`  Open tasks: ${d.open_tasks_count}`);
}

lines.push(
  '',
  '**Failures & Retries (last 24 h)**',
  `  Terminal failures: ${d.failed_captures_count}`,
  `  Retry events: ${d.retry_events_count}`,
);

return [{ json: { content: lines.join('\n') } }];
